// Inicialize um array para registrar o processo de depuração
let debugLog = [];

// Obtenha o primeiro item do array `body` corretamente
let requestBody = $input.first()?.json?.body;

// Se `body` for um array, pegamos o primeiro item dele
if (Array.isArray(requestBody)) {
    requestBody = requestBody[0]?.body; // Pega o objeto dentro do array
}

// Capturar o telefone corretamente
let phoneNumber = requestBody?.['contact[phone]'];

// Adicione log para depuração
debugLog.push(`Valor extraído: ${JSON.stringify(phoneNumber)}`);

// Verifique se o número foi definido e é uma string válida
if (!phoneNumber || typeof phoneNumber !== 'string' || phoneNumber.trim() === '') {
    throw new Error(`O número de telefone não foi fornecido ou está inválido. Valor recebido: ${JSON.stringify(phoneNumber)}`);
}

// Adicione o número inicial ao log de depuração
debugLog.push(`Número inicial: ${phoneNumber}`);

// Remova o sinal de "+" do número de telefone, caso exista
phoneNumber = phoneNumber.replace(/^\+/, '');
debugLog.push(`Número após remover "+": ${phoneNumber}`);

// **1. Ajustes para números brasileiros**
if (phoneNumber.startsWith("55")) {
    debugLog.push(`Número com prefixo 55 identificado: ${phoneNumber}`);

    let numberWithoutCountryCode = phoneNumber.slice(2);

    if (numberWithoutCountryCode.length === 11) {
        debugLog.push(`Número já contém 11 dígitos, mantido: ${phoneNumber}`);
        return { formattedPhoneNumber: phoneNumber, debugLog };
    }

    if (numberWithoutCountryCode.length === 10) {
        const formattedPhoneNumber = "55" + numberWithoutCountryCode.substring(0, 2) + "9" + numberWithoutCountryCode.substring(2);
        debugLog.push(`Número com 10 dígitos ajustado para 11: ${formattedPhoneNumber}`);
        return { formattedPhoneNumber, debugLog };
    }
} else {
    debugLog.push(`Número sem prefixo 55 identificado: ${phoneNumber}`);

    if (phoneNumber.length === 10) {
        const formattedPhoneNumber = "55" + phoneNumber.substring(0, 2) + "9" + phoneNumber.substring(2);
        debugLog.push(`Número com 10 dígitos ajustado para formato brasileiro: ${formattedPhoneNumber}`);
        return { formattedPhoneNumber, debugLog };
    }

    if (phoneNumber.length === 11) {
        const formattedPhoneNumber = "55" + phoneNumber;
        debugLog.push(`Número com 11 dígitos ajustado para formato brasileiro: ${formattedPhoneNumber}`);
        return { formattedPhoneNumber, debugLog };
    }
}

// Caso o número não se enquadre nas regras, retorne sem alterações
debugLog.push(`Número não ajustado, retornado como está: ${phoneNumber}`);
return { formattedPhoneNumber: phoneNumber, debugLog };

let items = $input.all(); // Obtenha todos os itens de entrada
let results = []; // Armazena os resultados processados

// Itere sobre cada item
for (let item of items) {
    let id_manychat;

    // Verifique se o valor do caminho data[0].id existe
    if (item.json.data && Array.isArray(item.json.data) && item.json.data[0] && item.json.data[0].id) {
        id_manychat = item.json.data[0].id; // Use o valor do primeiro caminho
    } 
    // Se o valor do primeiro caminho não existir, tente o segundo caminho
    else if (item.json.data && item.json.data.id) {
        id_manychat = item.json.data.id; // Use o valor do segundo caminho
    } 
    // Caso nenhum dos dois valores exista, atribua null ou um valor padrão
    else {
        id_manychat = null;
    }

    // Adicione o resultado ao array de resultados
    results.push({ json: { id_manychat } });
}

// Retorne todos os resultados
return results;

const opcoes = ['2', '5', '7', '10'];
const indice = Math.floor(Math.random() * opcoes.length);
const opcaoSelecionada = opcoes[indice];

return [
  {
    json: {
      opcao: opcaoSelecionada
    }
  }
];

